e hot", "category": "Extras", "price": 0.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": [{"ingredientName": "Large Hot Takeaway Cup", "qty": 1.0}]}, {"name": "Takeaway cup - cold", "category": "Extras", "price": 0.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": [{"ingredientName": "Cold Clear Takeaway Cup", "qty": 1.0}]}, {"name": "Medialuna DDL", "category": "Bakery", "price": 58.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": [{"ingredientName": "Medialuna DDL", "qty": 1.0}]}, {"name": "Medialuna Pastelera", "category": "Bakery", "price": 58.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": [{"ingredientName": "Medialuna Pastelera", "qty": 1.0}]}, {"name": "Croissant Choco", "category": "Bakery", "price": 75.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": [{"ingredientName": "Croissant Choco", "qty": 1.0}]}, {"name": "Croissant Frutos Rojos", "category": "Bakery", "price": 75.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": [{"ingredientName": "Croissant Frutos Rojos", "qty": 1.0}]}, {"name": "2x1 Mondays (cone)", "category": "Gelato", "price": 90.0, "ballCount": 2, "weightGrams": 0, "containerName": "Medium Cone", "recipe": []}, {"name": "2x1 Mondays (cup)", "category": "Gelato", "price": 90.0, "ballCount": 2, "weightGrams": 0, "containerName": "Medium Cup", "recipe": []}, {"name": "Vegan/Light Flavour", "category": "Extras", "price": 15.0, "ballCount": 0, "weightGrams": 0, "containerName": null, "recipe": []}]'::jsonb;
  v_item jsonb;
  v_recipe_entry jsonb;
  v_recipe jsonb;
  v_container_id uuid;
  v_ingredient_id uuid;
begin
  for v_item in select * from jsonb_array_elements(v_menu)
  loop
    v_recipe := '[]'::jsonb;

    for v_recipe_entry in select * from jsonb_array_elements(coalesce(v_item->'recipe', '[]'::jsonb))
    loop
      select id into v_ingredient_id from ingredients where name = v_recipe_entry->>'ingredientName';
      if v_ingredient_id is null then
        raise notice 'Skipping unknown ingredient % for menu item %', v_recipe_entry->>'ingredientName', v_item->>'name';
        continue;
      end if;
      v_recipe := v_recipe || jsonb_build_array(jsonb_build_object('ingredient_id', v_ingredient_id, 'qty', (v_recipe_entry->>'qty')::numeric));
    end loop;

    v_container_id := null;
    if v_item->>'containerName' is not null then
      select id into v_container_id from ingredients where name = v_item->>'containerName';
    end if;

    insert into menu_items (name, category, price, ball_count, weight_grams, container_id, recipe)
    values (
      v_item->>'name',
      v_item->>'category',
      (v_item->>'price')::numeric,
      coalesce((v_item->>'ballCount')::int, 0),
      coalesce((v_item->>'weightGrams')::int, 0),
      v_container_id,
      v_recipe
    );
  end loop;
end;
$$;
